+#[inline]
+fn clamp_destination_size_for_repair(
+    requested: usize,
+    dst_remaining: Option<usize>,
+    repair: bool,
+) -> (usize, bool) {
+    if !repair {
+        return (requested, false);
+    }
+    match dst_remaining {
+        Some(bound) if bound < requested => (bound, true),
+        _ => (requested, false),
+    }
